  margin: 0;
}

.phase-summaries__item {
  border-top: 1px solid var(--border-color);
}

.phase-summaries__item-header {
  display: flex;
  gap: 12px;
  align-items: baseline;
  padding: 8px 14px;
  cursor: pointer;
  font-size: 0.85rem;
}

.phase-summaries__item-number {
  color: var(--text-tertiary);
  font-family: monospace;
  min-width: 60px;
}

.phase-summaries__item-title {
  color: var(--text-primary);
  flex: 1;
}

.phase-summaries__item-status {
  font-size: 0.7rem;
  padding: 2px 8px;
  border-radius: 3px;
  background: var(--bg-tertiary);
  color: var(--text-secondary);
  text-transform: uppercase;
}

.phase-summaries__item-status--completed {
  color: var(--success-color, #4ade80);
}
.phase-summaries__item-status--failed {
  color: var(--error-color, #f87171);
}
.phase-summaries__item-status--executing {
  color: var(--warning-color, #fbbf24);
}

.phase-summaries__item-body {
  padding: 6px 14px 12px 86px;
  font-size: 0.85rem;
  color: var(--text-secondary);
  white-space: pre-wrap;
  margin: 0;
  line-height: 1.5;
}

.phase-summaries__item-time {
  display: block;
  padding: 0 14px 12px 86px;
  font-size: 0.7rem;
  color: var(--text-tertiary);
}
```

Use `var(--success-color, #4ade80)` style fallbacks per #110's discovery — semantic color tokens don't exist in the project's CSS variables.

### Vitest tests

File: `apps/desktop/src/components/__tests__/PhaseSummaries.test.tsx`

```ts
import { describe, it, expect } from 'vitest';
import { deriveSummaryRows } from '../detail/PhaseSummaries';
import type { EditorPlan } from '../detail/PlanEditor';

function mkPlan(overrides: Partial<EditorPlan> = {}): EditorPlan {
  return {
    schemaVersion: 1,
    issue: { number: 1, title: 'X' },
    createdAt: '2026-05-15T00:00:00Z',
    successCriteria: [],
    phases: [],
    coverageMatrix: {},
    ...overrides,
  };
}

describe('deriveSummaryRows', () => {
  it('returns empty array when plan is null', () => {
    expect(deriveSummaryRows(null)).toEqual([]);
  });

  it('filters out phases without a summary', () => {
    const plan = mkPlan({
      phases: [
        { number: 1, title: 'A', status: 'completed', content: '', verification: [], files: [], addressesCriteria: [], dependencies: [], summary: 'done' },
        { number: 2, title: 'B', status: 'pending', content: '', verification: [], files: [], addressesCriteria: [], dependencies: [] },
        { number: 3, title: 'C', status: 'completed', content: '', verification: [], files: [], addressesCriteria: [], dependencies: [], summary: '   ' }, // whitespace-only
      ],
    });
    const rows = deriveSummaryRows(plan);
    expect(rows).toHaveLength(1);
    expect(rows[0].number).toBe(1);
  });

  it('sorts by phase number ascending', () => {
    const plan = mkPlan({
      phases: [
        { number: 3, title: 'C', status: 'completed', content: '', verification: [], files: [], addressesCriteria: [], dependencies: [], summary: 'three' },
        { number: 1, title: 'A', status: 'completed', content: '', verification: [], files: [], addressesCriteria: [], dependencies: [], summary: 'one' },
        { number: 2, title: 'B', status: 'completed', content: '', verification: [], files: [], addressesCriteria: [], dependencies: [], summary: 'two' },
      ],
    });
    const rows = deriveSummaryRows(plan);
    expect(rows.map((r) => r.number)).toEqual([1, 2, 3]);
  });
});
```

### Out of scope this phase

- Mounting in IssueDetail — Phase 2.
- File diff viewer (the issue mentions "files created/modified" — that data is in the plan's `phases[i].files` array; rendering it as a chip list under each summary is a nice-to-have but skip it this release; phase summaries are the high-value bit).
- Plan-file deep linking (issue mentions "link to the relevant plan file") — out of scope for v0.6.2; PlanEditor already covers the edit case.

